import React, { useEffect, useState } from 'react'
import { useLocation, useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton } from "@coreui/react";
import authService from 'src/auth/auth.service';
import TextArea from 'src/utils/TextArea';
import GetBusinessDetails from 'src/components/services/GetBusinessDetails';
import GoBackComponent from 'src/utils/GoBackComponent';

function RemarksForm(props) {
    const { type, id } = props;
    const [formData, setFormData] = useState({ remarks: "" });
    const [editData, setEditData] = useState({});
    const [errors, setErrors] = useState({});
    const [userData] = useState(authService.getUserDetailsFromLocalStorage())
    const navigate = useNavigate();
    let location = useLocation();

    useEffect(() => {
        if(!location?.state?.businessQueryId) {
            navigate("/business")
        }
        if (type === "UPDATE") {
            fetchRemarksDataById(id);
        }
    }, [])

    const handleChange = (event) => {
        setFormData({ ...formData, [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' ') });
    };


    const fetchRemarksDataById = async (id) => {
        let data = {
            id: id,
            type: location?.state.type
        }
        let response = await GetBusinessDetails.getBusinessRemarksById(data);
        if (response?.code === 200) {
            // if(response?.results?.createrUserId === userData?._id || userData.email === "punam@wsegroup.in") {
            //     let data = {
            //         remarks: response?.results?.remarks
            //     }
            //     setFormData(data);
            // } else {
            //     navigate('/business/remarks', {state : { "businessQueryId": location?.state?.businessQueryId }})
            // }
            let data = {
                remarks: response?.results?.remarks
            }
            setFormData(data);
            setEditData(response?.results);
        }
    }

    const validateForm = () => {
        let errors = {};
        let formIsValid = true;
        if (formData.remarks === "") {
            errors['remarks'] = "Please enter remarks";
            formIsValid = false;
        }
        setErrors(errors);
        setTimeout(() => {
            setErrors({});
        }, 2000);
        return formIsValid;
    }

    const handleSubmit = async (event) => {
        event.preventDefault();
        if (validateForm()) {
            let postData = {
                remarks: formData?.remarks?.trim(),
                lastUpdatedBy: userData.name,
                type: location?.state?.type
            }
            if(location?.state?.type === "PAGE_QUERY") {
                postData.pageQueryId = location?.state?.businessQueryId;            
            } else {
                postData.businessQueryId = location?.state?.businessQueryId;
            }
            let response = {};
            if (type === "CREATE") {
                postData.createrUserId = userData?._id;
                postData.remarkedBy = userData?.name;
                response = await GetBusinessDetails.createBusinessRemarks(postData);
            } else {
                postData.id = id;
                response = await GetBusinessDetails.updateBusinessRemarks(postData);
            }
            if (response?.code === 201 || response?.code === 202) {
                navigate(`${location?.state?.type === "PAGE_QUERY" ? "/user-view-query" : "/business"}/remarks`, {state : { "businessQueryId": location?.state?.businessQueryId, type: location?.state?.type }})
            }
        }
    };

    return (
        <>
            <GoBackComponent goBackData={`${location?.state?.type === "PAGE_QUERY" ? "user-view-query" : "business"}/remarks`} goBackStateData={{ "businessQueryId": location?.state?.businessQueryId, type: location?.state?.type }} />
            <div className='customContainer'>
                <CForm className="row g-3">
                    <CCol md={12}>
                        <TextArea
                            value={formData.remarks}
                            label={"Remarks"}
                            required
                            name={"remarks"}
                            onChange={handleChange}
                            error={errors['remarks']}
                            disabled={!(props.type === "CREATE" || (props.type !== "CREATE" && (userData?.email === "punam@wsegroup.in" || ((userData._id === editData?.createrUserId) && editData?.editExpireTime > new Date().getTime() && editData?.businessQueryStatus !== "CLOSED"))))}
                        />
                    </CCol>

                    {(authService.getPermission(props.type === "CREATE" ? "REMARKS_CREATE" : "REMARKS_EDIT")) && (props.type === "CREATE" || (props.type !== "CREATE" && (userData?.email === "punam@wsegroup.in" || ((userData._id === editData?.createrUserId) && editData?.editExpireTime > new Date().getTime() && editData?.businessQueryStatus !== "CLOSED")))) &&
                        <CCol md={12}>
                            <CButton color="primary" onClick={handleSubmit} className="d-block">
                                {props.type === "CREATE" ? "Create" : "Update"}
                            </CButton>
                        </CCol>
                    }
                </CForm>
            </div>
        </>
    )
}

export default RemarksForm;
